#!/usr/bin/env node
/**
 * generate-readme-metrics.js
 *
 * Single source of truth for all README metrics.
 * Reads from docs/spec/capabilities.json (generated by generate-capabilities.js)
 * and injects into README.md.
 *
 * Zero tolerance for hardcoded numbers in README.
 *
 * Usage:
 *   node scripts/generate-readme-metrics.js          # update README
 *   node scripts/generate-readme-metrics.js --check   # CI mode: fail if drift detected
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, '..');
const README_PATH = path.join(ROOT, 'README.md');
const CAPABILITIES_PATH = path.join(ROOT, 'docs/spec/capabilities.json');

// Load capabilities (SSoT)
const capabilities = JSON.parse(fs.readFileSync(CAPABILITIES_PATH, 'utf8'));

const {
    static_pattern_count,
    threat_category_count,
    runtime_check_count,
    dependencies_runtime,
    mcp_tools
} = capabilities;

console.log('📊 Capabilities from SSoT:');
console.log(`  Categories: ${threat_category_count}`);
console.log(`  Patterns: ${static_pattern_count}`);
console.log(`  Checks: ${runtime_check_count}`);
console.log(`  Deps: ${dependencies_runtime}`);
console.log(`  MCP Tools: ${mcp_tools.length}`);

// Read README
let readme = fs.readFileSync(README_PATH, 'utf8');
let changes = [];

// 1. Update header metrics line: "32 threat categories · 352 static patterns · 26 runtime checks"
const headerMetricsRe = /(\d+) threat categories · (\d+) static patterns · (\d+) runtime checks/;
const newHeaderMetrics = `${threat_category_count} threat categories · ${static_pattern_count} static patterns · ${runtime_check_count} runtime checks`;
if (headerMetricsRe.test(readme)) {
    const oldMatch = readme.match(headerMetricsRe);
    if (oldMatch[0] !== newHeaderMetrics) {
        readme = readme.replace(headerMetricsRe, newHeaderMetrics);
        changes.push(`Header metrics: "${oldMatch[0]}" → "${newHeaderMetrics}"`);
    }
} else {
    console.error('❌ Could not find header metrics line in README');
    process.exit(1);
}

// 2. Update badge: runtime_deps-N_(ws)
const depsBadgeRe = /runtime_deps-(\d+)_\(ws\)/;
const newDepsBadge = `runtime_deps-${dependencies_runtime}_(ws)`;
if (depsBadgeRe.test(readme)) {
    const oldMatch = readme.match(depsBadgeRe);
    if (oldMatch[0] !== newDepsBadge) {
        readme = readme.replace(depsBadgeRe, newDepsBadge);
        changes.push(`Deps badge: "${oldMatch[0]}" → "${newDepsBadge}"`);
    }
}

// 3. Update capability table: "352 patterns, 32 categories"
const capTableRe = /`src\/scanner\.js`, `src\/patterns\.js` \((\d+) patterns, (\d+) categories\)/;
const newCapTable = `\`src/scanner.js\`, \`src/patterns.js\` (${static_pattern_count} patterns, ${threat_category_count} categories)`;
if (capTableRe.test(readme)) {
    const oldMatch = readme.match(capTableRe);
    if (oldMatch[0] !== newCapTable) {
        readme = readme.replace(capTableRe, newCapTable);
        changes.push(`Cap table: "${oldMatch[0]}" → "${newCapTable}"`);
    }
}

// 4. Update runtime guard: "(26 checks, 5 layers)"
const runtimeGuardRe = /\(26 checks, 5 layers\)/g;
const newRuntimeGuard = `(${runtime_check_count} checks, 5 layers)`;
if (runtimeGuardRe.test(readme)) {
    readme = readme.replace(runtimeGuardRe, newRuntimeGuard);
    changes.push(`Runtime guard: "(26 checks, 5 layers)" → "${newRuntimeGuard}"`);
}

// 5. Update MCP tools description: "352 patterns, 32 categories"
const mcpToolsRe = /scan a directory — (\d+) patterns, (\d+) categories/;
const newMcpTools = `scan a directory — ${static_pattern_count} patterns, ${threat_category_count} categories`;
if (mcpToolsRe.test(readme)) {
    const oldMatch = readme.match(mcpToolsRe);
    if (oldMatch[0] !== newMcpTools) {
        readme = readme.replace(mcpToolsRe, newMcpTools);
        changes.push(`MCP tools: "${oldMatch[0]}" → "${newMcpTools}"`);
    }
}

// 6. Update MCP tools count
const mcpToolsCountRe = /MCP server\.js \((\d+) tools\)/;
const newMcpToolsCount = `MCP server.js (${mcp_tools.length} tools)`;
if (mcpToolsCountRe.test(readme)) {
    const oldMatch = readme.match(mcpToolsCountRe);
    if (oldMatch[0] !== newMcpToolsCount) {
        readme = readme.replace(mcpToolsCountRe, newMcpToolsCount);
        changes.push(`MCP tools count: "${oldMatch[0]}" → "${newMcpToolsCount}"`);
    }
}

const isCheck = process.argv.includes('--check');

if (isCheck) {
    const current = fs.readFileSync(README_PATH, 'utf8');
    if (current !== readme) {
        console.error('\n❌ README metrics are out of sync!');
        console.error('\nChanges needed:');
        changes.forEach(c => console.error(`  - ${c}`));
        console.error('\nRun: node scripts/generate-readme-metrics.js');
        process.exit(1);
    }
    console.log('✅ README metrics are in sync with capabilities.json');
} else {
    if (changes.length === 0) {
        console.log('✅ README already in sync. No changes needed.');
    } else {
        fs.writeFileSync(README_PATH, readme);
        console.log('\n✅ README updated with changes:');
        changes.forEach(c => console.log(`  - ${c}`));
    }
}
